const e=document.getElementById("back-to-top");window.addEventListener("scroll",()=>{window.scrollY>400?(e.style.opacity="1",e.style.pointerEvents="auto"):(e.style.opacity="0",e.style.pointerEvents="none")});e.addEventListener("click",()=>window.scrollTo({top:0,behavior:"smooth"}));const t=document.getElementById("privacy-banner");localStorage.getItem("privacy-closed")&&(t.style.display="none");document.getElementById("privacy-close").addEventListener("click",()=>{t.style.display="none",localStorage.setItem("privacy-closed","1")});const n=document.getElementById("menu-toggle"),o=document.getElementById("mobile-menu");n?.addEventListener("click",()=>o?.classList.toggle("hidden"));
